approaches.code_java:
class Solution {
    public void reverseString(String[] s) {
        int n = s.length;
        String[] reversed = new String[n];
        for (int i = 0; i < n; i++) {
            reversed[i] = s[n - 1 - i];
        }
        for (int i = 0; i < n; i++) {
            s[i] = reversed[i];
        }
    }
}

